// Get all rows from Google Sheets
const rows = items.map(item => item.json);

// Group rows by CLIENT name
const grouped = {};

rows.forEach(row => {
  const client = row['CLIENT'] || 'UNKNOWN';

  if (!grouped[client]) {
    grouped[client] = [];
  }

  grouped[client].push({
    STATUS:              row['STATUS']              || '',
    'ACCOUNT NUMBER':    row['ACCOUNT NUMBER']      || '',
    CID:                 row['CID']                 || '',
    'ONU SN':            row['ONU SN']              || '',
    'SITE NAME':         row['SITE NAME']           || '',
    CLIENT:              row['CLIENT']              || '',
    'SITE ADDRESS':      row['SITE ADDRESS']        || '',
    'DEVICE MODEL':      row['DEVICE MODEL']        || '',
    SERIAL:              row['SERIAL']              || '',
    MODEL:               row['MODEL']               || '',
    'IP BLOCK':          row['IP BLOCK']            || '',
    'WAN PARENT SUBNET': row['WAN PARENT SUBNET']   || '',
    VLAN:                row['VLAN']                || '',
    TERMINATION:         row['TERMINATION']         || '',
    DEVICE:              row['DEVICE']              || '',
    'NPE UPLINK':        row['NPE UPLINK']          || '',
    'NPE REMOTE IP':     row['NPE REMOTE IP']       || '',
    'GLOBE CIRCUIT ID':  row['GLOBE CIRCUIT ID']    || '',
    PLAN:                row['PLAN']                || '',
    POC:                 row['POC']                 || '',
    CONTACT:             row['CONTACT']             || '',
  });
});

// Return as single item
return [{ json: grouped }];
